"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import type * as React from "react";
import { cn } from "@/lib/utils";
import { focusRing, colorTransition } from "@/lib/recipes";

export interface CardProps extends useRender.ComponentProps<"div"> {
  /** Show a visible border. */
  border?: boolean;
  /** Add a subtle hover state (bg shift + optional border darken). */
  hoverable?: boolean;
  /** Add an elevation shadow. */
  shadow?: boolean;
  /** Sit on the next surface step up. Use for cards nested inside another card. */
  secondary?: boolean;
  /** Render hairline dividers between direct children (list container). */
  borderBetween?: boolean;
  /** Layout direction. */
  direction?: "column" | "row";
  /**
   * When true, the border adopts `--primary` for a definitive selected
   * state (multi-pick galleries, plan comparison). Also sets `aria-selected`.
   */
  selected?: boolean;
}

/**
 * Card: a surface primitive. Rounded, tokenized, hairline-bordered by
 * default. Compose with boolean props (`border`, `hoverable`, `shadow`,
 * `secondary`, `borderBetween`, `direction`) to fit the surface you need.
 *
 * Card is intentionally content-agnostic: for structured header/content/
 * footer layouts (settings pages, plan pickers), reach for `Section`.
 */
export function Card({
  className,
  border = true,
  hoverable,
  shadow,
  secondary,
  borderBetween,
  direction = "column",
  selected,
  render,
  ...props
}: CardProps): React.ReactElement {
  const defaultProps = {
    className: cn(
      "relative flex rounded-[var(--radius-12)] text-ink",
      direction === "column" ? "flex-col" : "flex-row",
      // Default card sits at --surface-elevated, matching the popup /
      // menu / modal surface (pure white in light mode, palette rung
      // in dark). Secondary lives at surface-1 for nested cards inside
      // another elevated card.
      secondary ? "bg-surface-1" : "bg-surface-elevated",
      border && "border border-hairline",
      shadow && "shadow-card",
      hoverable && [
        "cursor-pointer",
        // Subtle hover tint that reads as "same surface, slightly
        // shifted" rather than dropping a rung. Border stays stable
        // so the whole card doesn't animate on hover.
        secondary ? "hover:bg-surface-1" : "hover:bg-surface-elevated-hover",
        focusRing,
      ],
      borderBetween &&
        (direction === "column"
          ? "[&>*+*]:border-t [&>*+*]:border-hairline"
          : "[&>*+*]:border-l [&>*+*]:border-hairline"),
      selected && "!border-primary",
      colorTransition,
      className,
    ),
    "data-slot": "card",
    "data-selected": selected || undefined,
    "aria-selected": selected || undefined,
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}
